import React, { useState } from 'react';
import './AddVendor.css';

const AddVendor = ({ handleAddVendor }) => {
  const [newVendor, setNewVendor] = useState({
    name: '',
    field: '',
    mail: '',
    tel: '',
    contactname: ''
    // Add additional fields as needed for the vendor
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewVendor((prevVendor) => ({
      ...prevVendor,
      [name]: value,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAddVendor(newVendor);
    resetForm();
  };

  const resetForm = () => {
    setNewVendor({
      name: '',
      field: '',
      mail: '',
      tel: '',
      contactname: ''
      // Reset additional fields as needed for the vendor
    });
  };

  return (
    <div className="add-vendor-container">
      <h2 className="add-vendor-heading">Add Vendor</h2>
      <form className="add-vendor-form" onSubmit={handleSubmit}>
        <div className="form-group">
          <label htmlFor="name">Name:</label>
          <input
            type="text"
            id="name"
            name="name"
            value={newVendor.name}
            onChange={handleInputChange}
            required
          />
        </div>
        <div className="form-group">
          <label htmlFor="email">Email:</label>
          <input
            type="email"
            id="email"
            name="email"
            value={newVendor.email}
            onChange={handleInputChange}
            required
          />
        </div>
        {/* Add additional form inputs for vendor information */}
        <button type="submit" className="add-vendor-btn">
          Add Vendor
        </button>
      </form>
    </div>
  );
};

export default AddVendor;
